import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useSelector, useDispatch } from 'react-redux';
import { fetchUserPosts } from '../redux/thunks/postThunks';
import { clearUserPosts } from '../redux/slices/postSlice';
import friendService from '../api/services/friendService';
import { NODE_API } from '../api/config';
import { toast } from 'react-toastify';
import PostCard from '../components/posts/PostCard';
import './UserProfile.css';

const UserProfile = () => {
  const { userId } = useParams();
  const { user: me } = useSelector((state) => state.auth);
  const { userPosts, hasMoreUser } = useSelector((state) => state.posts);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [friendStatus, setFriendStatus] = useState('none'); // none, pending, friends

  useEffect(() => {
    if (userId === me?._id) {
      navigate('/profile', { replace: true });
      return;
    }

    const loadProfile = async () => {
      setLoading(true);
      try {
        const res = await friendService.getOtherProfile({ userId });
        setProfile(res.data?.data?.customerData || res.data?.data || res.data);

        // Check friend status — .NET returns { StatusCode, Data: true/false, Message }
        const friendRes = await friendService.isFriend({ userId, myId: me?._id });
        const friendData = friendRes.data;
        const isFriendResult = friendData?.Data ?? friendData?.data ?? false;
        if (isFriendResult === true) setFriendStatus('friends');
        else setFriendStatus('none');
      } catch (error) {
        toast.error('Failed to load profile');
      }
      setLoading(false);
    };

    loadProfile();
    dispatch(clearUserPosts());
    dispatch(fetchUserPosts({ userId, skip: 0, limit: 20 }));

    return () => { dispatch(clearUserPosts()); };
  }, [userId, me, dispatch, navigate]);

  const getImageUrl = (path) => {
    if (!path) return null;
    if (path.startsWith('http')) return path;
    return `${NODE_API}/${path}`;
  };

  const handleAddFriend = async () => {
    try {
      await friendService.sendFriendRequest({ friendId: userId });
      setFriendStatus('pending');
      toast.success('Friend request sent!');
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to send request');
    }
  };

  if (loading) {
    return <div className="page-loading"><div className="page-loading-spinner" /></div>;
  }

  const name = profile?.fullName || 'User';
  const bannerUrl = getImageUrl(profile?.bannerURL?.original || profile?.bannerURL);
  const avatarUrl = getImageUrl(profile?.imageURL?.original || profile?.imageURL?.thumbnail || profile?.imageURL);

  return (
    <div className="user-profile-page">
      <div className="user-profile-top">
        <button className="user-back-btn" onClick={() => navigate(-1)}>←</button>
      </div>

      <div
        className="profile-banner"
        style={bannerUrl ? { backgroundImage: `url(${bannerUrl})` } : {}}
      >
        {!bannerUrl && <div className="profile-banner-gradient" />}
      </div>

      <div className="profile-info-section">
        <div className="profile-avatar-wrap">
          {avatarUrl ? (
            <img src={avatarUrl} alt="Profile" className="profile-avatar" />
          ) : (
            <div className="profile-avatar-placeholder">{name[0].toUpperCase()}</div>
          )}
        </div>
        <h1 className="profile-name">{name}</h1>
        {(profile?.city || profile?.state || profile?.country) && (
          <p className="profile-location">
            📍 {[profile.city, profile.state, profile.country].filter(Boolean).join(', ')}
          </p>
        )}
        {profile?.about && <p className="profile-bio">{profile.about}</p>}

        <div className="user-profile-actions">
          {friendStatus === 'friends' && (
            <button className="user-action-btn" onClick={() => navigate(`/chat/${userId}`)}>
              💬 Message
            </button>
          )}
          {friendStatus === 'pending' && (
            <button className="user-action-btn user-action-pending" disabled>
              ⏳ Request Sent
            </button>
          )}
          {friendStatus === 'none' && (
            <button className="user-action-btn" onClick={handleAddFriend}>
              ➕ Add Friend
            </button>
          )}
        </div>
      </div>

      <div className="profile-posts-section">
        <h3 className="profile-posts-title">Posts</h3>
        {userPosts.length === 0 && (
          <div className="profile-posts-empty"><p>No posts yet</p></div>
        )}
        {userPosts.map((post) => (
          <PostCard key={post._id} post={post} />
        ))}
        {hasMoreUser && userPosts.length > 0 && (
          <button className="home-load-more" onClick={() => dispatch(fetchUserPosts({ userId, skip: userPosts.length, limit: 20 }))}>
            Load More
          </button>
        )}
      </div>
    </div>
  );
};

export default UserProfile;
